sql:
SELECT 
  (SELECT COUNT(*) FROM models WHERE is_active = 1) AS active_models_count,
  (SELECT SUM(size_mb) FROM datasets) AS total_datasets_size_mb;

external_knowledge:
- "Primordial soup of data" metaphorically refers to datasets used for training;
- "Nourished by datasets larger than a mere 10 megabytes" signifies datasets with a size greater than 10 MB;
- "Dawn of sixty or more days since their training began" refers to the training date being more than 60 days ago.

sql:
SELECT COUNT(DISTINCT model_id) AS total_models_with_training
FROM trainings
WHERE training_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT COUNT(DISTINCT model_id) AS peak_count
FROM performance_metrics
WHERE precision = (SELECT MAX(precision) FROM performance_metrics);
